     4→
     5→/** Formater une date en français */
     6→export function formatDateFR(dateStr: string): string {
     7→  return new Date(dateStr).toLocaleDateString('fr-FR', {
     8→    day: 'numeric',
     9→    month: 'long',
    10→    year: 'numeric',
    11→  })
    12→}
    13→
    14→/** Formater une date relative (il y a X minutes/heures/jours) */
    15→export function formatRelativeDate(dateStr: string): string {
    16→  const now = new Date()
    17→  const date = new Date(dateStr)
    18→  const diffMs = now.getTime() - date.getTime()
    19→  const diffMinutes = Math.floor(diffMs / 60000)
    20→  const diffHours = Math.floor(diffMs / 3600000)
    21→  const diffDays = Math.floor(diffMs / 86400000)
    22→
    23→  if (diffMinutes < 1) return "À l'instant"
    24→  if (diffMinutes < 60) return `Il y a ${diffMinutes} min`
    25→  if (diffHours < 24) return `Il y a ${diffHours}h`
    26→  if (diffDays < 7) return `Il y a ${diffDays}j`
    27→  return formatDateFR(dateStr)
    28→}
    29→
    30→/** Formater un prix en euros (centimes → euros) */
    31→export function formatPrice(cents: number): string {
    32→  return new Intl.NumberFormat('fr-FR', {
    33→    style: 'currency',
    34→    currency: 'EUR',
    35→  }).format(cents / 100)
    36→}
    37→
    38→/** Formater un nombre avec séparateur de milliers */
    39→export function formatNumber(n: number): string {
    40→  return new Intl.NumberFormat('fr-FR').format(n)
    41→}
    42→
    43→/** Extraire le domaine d'une URL */
    44→export function extractDomain(url: string): string {
    45→  try {
    46→    const parsed = new URL(url.startsWith('http') ? url : `https://${url}`)
    47→    return parsed.hostname.replace('www.', '')
    48→  } catch {
    49→    return url
    50→  }
    51→}
    52→
    53→/** Valider une URL */
    54→export function isValidUrl(url: string): boolean {
    55→  try {
    56→    const parsed = new URL(url.startsWith('http') ? url : `https://${url}`)
    57→    return parsed.protocol === 'https:' || parsed.protocol === 'http:'
    58→  } catch {
    59→    return false
    60→  }
    61→}
