    63→/** Obtenir le grade AEO à partir du score */
    64→export function getGradeFromScore(score: number): 'A+' | 'A' | 'B' | 'C' | 'D' | 'F' {
    65→  if (score >= 90) return 'A+'
    66→  if (score >= 80) return 'A'
    67→  if (score >= 65) return 'B'
    68→  if (score >= 50) return 'C'
    69→  if (score >= 30) return 'D'
    70→  return 'F'
    71→}
    72→
    73→/** Obtenir la couleur Tailwind associée au grade */
    74→export function getGradeColor(grade: string): string {
    75→  switch (grade) {
    76→    case 'A+': case 'A': return 'text-score-excellent'
    77→    case 'B': return 'text-score-good'
    78→    case 'C': return 'text-score-average'
    79→    case 'D': case 'F': return 'text-score-poor'
    80→    default: return 'text-slate-400'
    81→  }
    82→}
    83→
    84→/** Obtenir la couleur de fond associée au score */
    85→export function getScoreColor(score: number): string {
    86→  if (score >= 80) return '#10B981'
    87→  if (score >= 65) return '#3B82F6'
    88→  if (score >= 50) return '#F59E0B'
    89→  return '#EF4444'
    90→}
